INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('SCI_SE2b_L3_A', 'SCI_SE2b', 3, 'A', 'Discern (Anomaly Detection)', NULL, '2 different balls, ramp (book/board)', 'rolled socks, cardboard', 'Risk_Level_A', 'Safe for independent work.', 'Variation A: "Show me how Asking Testable Questions works physically. If I do [X], what should happen according to the rules of science?"', 'Child identifies the mechanical error and explains how Asking Testable Questions really works.', 'Child agrees with the flawed reasoning. Parent prompts them to think about physical variables.', 'What was the mechanical error?', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden","savanna","wetland"],"food":["matooke","mangoes","chapati","jackfruit"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('SCI_SE2b_L3_B', 'SCI_SE2b', 3, 'B', 'Discern (Anomaly Detection)', NULL, '2 different balls, ramp (book/board)', 'rolled socks, cardboard', 'Risk_Level_A', 'Safe for independent work.', 'Variation B: "Amara claims that Asking Testable Questions works because of magic. Explain the real physical mechanism to her."', 'Child identifies the mechanical error and explains how Asking Testable Questions really works.', 'Child agrees with the flawed reasoning. Parent prompts them to think about physical variables.', 'What was the mechanical error?', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden","savanna","wetland"],"food":["matooke","mangoes","chapati","jackfruit"]}}', 0);
